#include <stdio.h>

static void swap_ints(int *left, int *right) {
    int temporary = *left;
    *left = *right;
    *right = temporary;
}

int main(void) {
    int a, b;
    if (scanf("%d %d", &a, &b) != 2) return 1;
    swap_ints(&a, &b);
    printf("%d %d\n", a, b);
    return 0;
}
